+  void doConvexDecomposition(unsigned int           vcount,
+                                  const double           *vertices,
+                                  unsigned int           tcount,
+                                  const unsigned int    *indices,
+                                  ConvexDecompInterface *callback,
+                                  double                  masterVolume,
+                                  unsigned int           depth)
+
+  {
+
+    double plane[4];
+
+    bool split = false;
+
+
+    if ( depth < MAXDEPTH )
