+	bool IsSame(const Vector3d<double> &v,double epsilon) const
+	{
+		double dx = fabsf( x - v.x );
+		if ( dx > epsilon ) return false;
+		double dy = fabsf( y - v.y );
+		if ( dy > epsilon ) return false;
