+	double ComputeNormal(const Vector3d<double> &A,
+										 const Vector3d<double> &B,
+										 const Vector3d<double> &C)
+	{
+		double vx,vy,vz,wx,wy,wz,vw_x,vw_y,vw_z,mag;
+
+		vx = (B.x - C.x);
+		vy = (B.y - C.y);
+		vz = (B.z - C.z);
+
+		wx = (A.x - B.x);
+		wy = (A.y - B.y);
+		wz = (A.z - B.z);
+
+		vw_x = vy * wz - vz * wy;
+		vw_y = vz * wx - vx * wz;
+		vw_z = vx * wy - vy * wx;
+
+		mag = sqrtf((vw_x * vw_x) + (vw_y * vw_y) + (vw_z * vw_z));
+
+		if ( mag < 0.000001f )
+		{
+			mag = 0;
+		}
+		else
+		{
+			mag = 1.0f/mag;
+		}
+
+		x = vw_x * mag;
+		y = vw_y * mag;
+		z = vw_z * mag;
+
+		return mag;
+	}
