+/** Computes the reflection vector between two vectors.*/
+	void Reflection(const Vector3d<Type> &a,const Vector3d<Type> &b)// compute reflection vector.
+	{
+		Vector3d<double> c;
+		Vector3d<double> d;
+
+		double dot = a.Dot(b) * 2.0f;
+
+		c = b * dot;
+
+		d = c - a;
+
+		x = -d.x;
+		y = -d.y;
+		z = -d.z;
+	};
