+	inline double Normalize(void)       // normalize to a unit vector, returns distance.
+	{
+		double d = sqrtf( static_cast< double >( x*x + y*y + z*z ) );
+		if ( d > 0 )
+		{
+			double r = 1.0f / d;
+			x *= r;
+			y *= r;
+			z *= r;
+		}
+		else
+		{
+			x = y = z = 1;
+		}
+		return d;
