+static inline double DistToPt(const double *p,const double *plane)
+{
+	double x = p[0];
+	double y = p[1];
+	double z = p[2];
+	double d = x*plane[0] + y*plane[1] + z*plane[2] + plane[3];
+	return d;
+}
+
