+
+  dx = dia2[0]-center[0]; /* x component of radius vector */
+  dy = dia2[1]-center[1]; /* y component of radius vector */
+  dz = dia2[2]-center[2]; /* z component of radius vector */
+
+  mRadius2 = dx*dx + dy*dy + dz*dz;
+  mRadius = double(sqrt(mRadius2));
