+void fm_eulerToQuat(double roll,double pitch,double yaw,double *quat) // convert euler angles to quaternion.
+{
+	roll  *= 0.5f;
+	pitch *= 0.5f;
+	yaw   *= 0.5f;
+
+	double cr = cos(roll);
+	double cp = cos(pitch);
+	double cy = cos(yaw);
+
+	double sr = sin(roll);
+	double sp = sin(pitch);
+	double sy = sin(yaw);
+
+	double cpcy = cp * cy;
+	double spsy = sp * sy;
+	double spcy = sp * cy;
+	double cpsy = cp * sy;
+
+	quat[0]   = ( sr * cpcy - cr * spsy);
+	quat[1]   = ( cr * spcy + sr * cpsy);
+	quat[2]   = ( cr * cpsy - sr * spcy);
+	quat[3]   = cr * cpcy + sr * spsy;
+}
