+public:
+  VertexPosition(void) { };
+  VertexPosition(const double *p)
+  {
+  	mPos[0] = p[0];
+  	mPos[1] = p[1];
+  	mPos[2] = p[2];
+  };
+
+	void Set(int index,const double *pos)
+	{
+		const double * p = &pos[index*3];
+
+		mPos[0]    = p[0];
+		mPos[1]    = p[1];
+		mPos[2]    = p[2];
+
+	};
+
+  double GetX(void) const { return mPos[0]; };
+  double GetY(void) const { return mPos[1]; };
+  double GetZ(void) const { return mPos[2]; };
+
+	double mPos[3];
