+    radius = 0;
+  };
+  bool initXml(TiXmlElement *);
+};
+
+class Box : public Geometry
+{
+public:
+  Box() { this->clear(); };
+  Vector3 dim;
+
+  void clear()
+  {
+    dim.clear();
+  };
+  bool initXml(TiXmlElement *);
+};
+
+class Cylinder : public Geometry
+{
+public:
+  Cylinder() { this->clear(); };
+  double length;
+  double radius;
+
+  void clear()
+  {
+    length = 0;
+    radius = 0;
+  };
