+bool getBestFitPlane(unsigned int vcount,
+                     const double *points,
+                     unsigned int vstride,
+                     const double *weights,
+                     unsigned int wstride,
+                     double *plane)
+{
+  bool ret = false;
+
+  Vec3 kOrigin(0,0,0);
+
+  double wtotal = 0;
+
+  if ( 1 )
+  {
+    const char *source  = (const char *) points;
+    const char *wsource = (const char *) weights;
+
+    for (unsigned int i=0; i<vcount; i++)
+    {
+
+      const double *p = (const double *) source;
+
+      double w = 1;
+
+      if ( wsource )
+      {
+        const double *ws = (const double *) wsource;
+        w = *ws; //
+        wsource+=wstride;
+      }
+
+      kOrigin.x+=p[0]*w;
+      kOrigin.y+=p[1]*w;
+      kOrigin.z+=p[2]*w;
+
+      wtotal+=w;
+
+      source+=vstride;
+    }
+  }
+
+  double recip = 1.0f / wtotal; // reciprocol of total weighting
+
+  kOrigin.x*=recip;
+  kOrigin.y*=recip;
+  kOrigin.z*=recip;
+
+
+  double fSumXX=0;
+  double fSumXY=0;
+  double fSumXZ=0;
+
+  double fSumYY=0;
+  double fSumYZ=0;
+  double fSumZZ=0;
+
+
+  if ( 1 )
+  {
+    const char *source  = (const char *) points;
+    const char *wsource = (const char *) weights;
+
+    for (unsigned int i=0; i<vcount; i++)
+    {
+
+      const double *p = (const double *) source;
+
+      double w = 1;
+
+      if ( wsource )
+      {
+        const double *ws = (const double *) wsource;
+        w = *ws; //
+        wsource+=wstride;
+      }
+
+      Vec3 kDiff;
+
+      kDiff.x = w*(p[0] - kOrigin.x); // apply vertex weighting!
+      kDiff.y = w*(p[1] - kOrigin.y);
+      kDiff.z = w*(p[2] - kOrigin.z);
+
+      fSumXX+= kDiff.x * kDiff.x; // sume of the squares of the differences.
+      fSumXY+= kDiff.x * kDiff.y; // sume of the squares of the differences.
+      fSumXZ+= kDiff.x * kDiff.z; // sume of the squares of the differences.
+
+      fSumYY+= kDiff.y * kDiff.y;
+      fSumYZ+= kDiff.y * kDiff.z;
+      fSumZZ+= kDiff.z * kDiff.z;
+
+
+      source+=vstride;
+    }
+  }
+
+  fSumXX *= recip;
+  fSumXY *= recip;
+  fSumXZ *= recip;
+  fSumYY *= recip;
+  fSumYZ *= recip;
+  fSumZZ *= recip;
+
+  // setup the eigensolver
+  Eigen kES;
+
+  kES.mElement[0][0] = fSumXX;
+  kES.mElement[0][1] = fSumXY;
+  kES.mElement[0][2] = fSumXZ;
+
+  kES.mElement[1][0] = fSumXY;
+  kES.mElement[1][1] = fSumYY;
+  kES.mElement[1][2] = fSumYZ;
+
+  kES.mElement[2][0] = fSumXZ;
+  kES.mElement[2][1] = fSumYZ;
+  kES.mElement[2][2] = fSumZZ;
+
+  // compute eigenstuff, smallest eigenvalue is in last position
+  kES.DecrSortEigenStuff();
