+  Vec3 kNormal;
+
+  kNormal.x = kES.mElement[0][2];
+  kNormal.y = kES.mElement[1][2];
+  kNormal.z = kES.mElement[2][2];
+
+  // the minimum energy
+  plane[0] = kNormal.x;
+  plane[1] = kNormal.y;
+  plane[2] = kNormal.z;
+
+  plane[3] = 0 - kNormal.dot(kOrigin);
+
+  return ret;
+}
