+		mag = sqrt((vw_x * vw_x) + (vw_y * vw_y) + (vw_z * vw_z));
+
+		if ( mag < 0.000001f )
+		{
+			mag = 0;
+		}
+		else
+		{
+			mag = 1.0f/mag;
+		}
+
+		x = vw_x * mag;
+		y = vw_y * mag;
+		z = vw_z * mag;
+
+
+		double D = 0.0f - ((x*A.x)+(y*A.y)+(z*A.z));
+
+		return D;
+	}
