+bool computeSplitPlane(unsigned int vcount,
+                       const double *vertices,
+                       unsigned int tcount,
+                       const unsigned int *indices,
+                       ConvexDecompInterface *callback,
+                       double *plane)
+{
+  bool cret = false;
+
+
+  double sides[3];
+  double matrix[16];
+
+  computeBestFitOBB( vcount, vertices, sizeof(double)*3, sides, matrix );
+
+  double bmax[3];
+  double bmin[3];
+
+  bmax[0] = sides[0]*0.5f;
+  bmax[1] = sides[1]*0.5f;
+  bmax[2] = sides[2]*0.5f;
+
+  bmin[0] = -bmax[0];
+  bmin[1] = -bmax[1];
+  bmin[2] = -bmax[2];
