+template<>
+bool VertexLess<VertexPosition>::operator()(int v1,int v2) const
+{
+  bool ret = false;
+
+	const VertexPosition& a = Get(v1);
+	const VertexPosition& b = Get(v2);
+
+  RDIFF d = relativeDiff(a.mPos,b.mPos,0.0001f);
+  if ( d == RD_LESS ) ret = true;
+
+  return ret;
+
