+		strcpy(ret,"-1");
+	}
+	else
+	{
+		sprintf(ret,"%.9f", v );
+		const char *dot = strstr(ret,".");
+		if ( dot )
+		{
+			int len = (int)strlen(ret);
+		  char *foo = &ret[len-1];
+			while ( *foo == '0' ) foo--;
+			if ( *foo == '.' )
+				*foo = 0;
+			else
+				foo[1] = 0;
+		}
+	}
+
+	return ret;
