+  double radius;
+
+  void clear()
+  {
+    radius = 0;
+  };
+  bool initXml(TiXmlElement *);
+};
+
+class Box : public Geometry
+{
+public:
+  Box() { this->clear(); };
+  Vector3 dim;
+
+  void clear()
+  {
+    dim.clear();
+  };
+  bool initXml(TiXmlElement *);
+};
+
+class Cylinder : public Geometry
+{
+public:
+  Cylinder() { this->clear(); };
+  double length;
+  double radius;
+
+  void clear()
+  {
+    length = 0;
+    radius = 0;
+  };
+  bool initXml(TiXmlElement *);
+};
+
+class Mesh : public Geometry
+{
+public:
+  Mesh() { this->clear(); };
+  std::string filename;
+  Vector3 scale;
+
+  void clear()
+  {
+    filename.clear();
+    // default scale
+    scale.x = 1;
+    scale.y = 1;
+    scale.z = 1;
+  };
+  bool initXml(TiXmlElement *);
+};
+
+class Material
+{
+public:
+  Material() { this->clear(); };
+  std::string name;
+  std::string texture_filename;
+  Color color;
+
+  void clear()
+  {
+    color.clear();
+    texture_filename.clear();
+    name.clear();
+  };
+  bool initXml(TiXmlElement* config);
+};
+
+class Inertial
+{
+public:
+  Inertial() { this->clear(); };
+  Pose origin;
+  double mass;
+  double ixx,ixy,ixz,iyy,iyz,izz;
+
+  void clear()
+  {
+    origin.clear();
+    mass = 0;
+    ixx = ixy = ixz = iyy = iyz = izz = 0;
+  };
+  bool initXml(TiXmlElement* config);
+};
+
+class Visual
+{
+public:
+  Visual() { this->clear(); };
+  Pose origin;
+  boost::shared_ptr<Geometry> geometry;
+
+  std::string material_name;
+  boost::shared_ptr<Material> material;
+
+  void clear()
+  {
+    origin.clear();
+    material_name.clear();
+    material.reset();
+    geometry.reset();
+  };
+  bool initXml(TiXmlElement* config);
+};
+
+class Collision
+{
+public:
+  Collision() { this->clear(); };
+  Pose origin;
+  boost::shared_ptr<Geometry> geometry;
+
+  void clear()
+  {
+    origin.clear();
+    geometry.reset();
+  };
+  bool initXml(TiXmlElement* config);
+};
+
+
+class Link
+{
+public:
+  Link() { this->clear(); };
+
+  std::string name;
+
+  /// inertial element
+  boost::shared_ptr<Inertial> inertial;
+
+  /// visual element
+  boost::shared_ptr<Visual> visual;
+
+  /// collision element
+  boost::shared_ptr<Collision> collision;
+
+  /// Parent Joint element
+  ///   explicitly stating "parent" because we want directional-ness for tree structure
+  ///   every link can have one parent
+  boost::shared_ptr<Joint> parent_joint;
+  /// Get Parent Link throught the Parent Joint
+  boost::shared_ptr<Link> parent_link;
+
+  std::vector<boost::shared_ptr<Joint> > child_joints;
+  std::vector<boost::shared_ptr<Link> > child_links;
+
+  bool initXml(TiXmlElement* config);
+  void setParent(boost::shared_ptr<Link> parent);
+
+  void clear()
+  {
+    this->name.clear();
+    this->inertial.reset();
+    this->visual.reset();
+    this->collision.reset();
+    this->parent_joint.reset();
+    this->parent_link.reset();
+    this->child_joints.clear();
+    this->child_links.clear();
+  };
+  void setParentJoint(boost::shared_ptr<Joint> child);
+  void addChild(boost::shared_ptr<Link> child);
+  void addChildJoint(boost::shared_ptr<Joint> child);
+};
+
+
+
+
+}
+
+#endif

